      | "InternalServerErrorException" ->
          `InternalServerErrorException
            (InternalServerErrorException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `BadRequestException e ->
          `Assoc
            [("error", (`String "BadRequestException"));
            ("details", (BadRequestException.to_json e))]
      | `InternalServerErrorException e ->
          `Assoc
            [("error", (`String "InternalServerErrorException"));
            ("details", (InternalServerErrorException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("name", (Option.map x.name ~f:FilterName.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let name =
        (Option.map ~f:FilterName.of_xml) (Xml.child xml_arg0 "name") in
      make ?name ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let name = field_map json__ "Name" FilterName.of_json in make ?name ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Creates a filter using the specified finding criteria. The maximum number of saved filters per Amazon Web Services account per Region is 100. For more information, see Quotas for GuardDuty."]
